1510       U->replaceAllUsesWith(Sub);
1511       Changed = true;
1512     } else if (match(U, m_ExtractValue<1>(m_Value()))) {
1513       U->replaceAllUsesWith(Builder.getFalse());
1514       Changed = true;
1515     } else
1516       continue;
1517 
