1089               Cmp->getOperand(0), Cmp->getOperand(1)));
1090           continue;
1091         }
1092         if (IsOr && match(Cur, m_LogicalOr(m_Value(Op0), m_Value(Op1)))) {
1093           QueueValue(Op1);
1094           QueueValue(Op0);
1095           continue;
1096         }
1097         if (IsAnd && match(Cur, m_LogicalAnd(m_Value(Op0), m_Value(Op1)))) {
1098           QueueValue(Op1);
1099           QueueValue(Op0);
