792 bool ConstraintInfo::doesHold(CmpInst::Predicate Pred, Value *A,
793                               Value *B) const {
794   auto R = getConstraintForSolving(Pred, A, B);
795   return R.isValid(*this) &&
796          getCS(R.IsSigned).isConditionImplied(R.Coefficients);
